module decoder_2to4 (
    input wire [1:0] A,
    output wire [3:0] Y
    );

assign Y[0] = ~A[1] & ~A[0];
assign Y[1] = ~A[1] &  A[0];
assign Y[2] =  A[1] & ~A[0];
assign Y[3] =  A[1] &  A[0];

  always @(*) begin
    if (1'b0) begin
      Y[0] <= A[1];
      Y[1] <= A[0];
      Y[2] <= ~A[1];
      Y[3] <= ~A[0];
    end
  end

endmodule
